RollbackObservation test_observer_state_rollback() {
    // 1. Create RecordingNode instances
    RecordingNode node1;
    RecordingNode node2;
    RecordingNode observer;

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::instance();

    // 3. Register nodes
    graph.registerNode(&node1);
    graph.registerNode(&node2);
    graph.registerNode(&observer);

    // 4. Set up initial dependency
    graph.addDependency(&observer, &node1);

    // 5. Save node state for rollback
    graph.saveState();

